using UnityEngine;
using UnityEditor;
public class Script {
  public static object Main() {
    var sb = new System.Text.StringBuilder();

    // Find the spindle controller
    var spindle = GameObject.FindFirstObjectByType<CNC2SpindleController>();
    if (spindle == null) return "CNC2SpindleController not found";

    // Dump full hierarchy inside spindleHolder (3 levels deep)
    sb.AppendLine("Children of spindleHolder:");
    DumpChildren(spindle.transform, sb, 0, 4);

    // Find cncCutter
    Transform cncCutter = spindle.transform.parent;
    while (cncCutter != null && cncCutter.name != "cncCutter") cncCutter = cncCutter.parent;

    // Wire _cncCutter via SerializedObject
    var so = new SerializedObject(spindle);
    so.Update();
    var cutterProp = so.FindProperty("_cncCutter");
    if (cutterProp != null && cncCutter != null) {
      cutterProp.objectReferenceValue = cncCutter;
      sb.AppendLine("\nWired _cncCutter = " + cncCutter.name);
    } else {
      sb.AppendLine("\n_cncCutter prop: " + (cutterProp == null ? "NOT FOUND" : "found") + "  cncCutter GO: " + (cncCutter == null ? "NOT FOUND" : cncCutter.name));
    }
    so.ApplyModifiedProperties();

    UnityEditor.SceneManagement.EditorSceneManager.SaveOpenScenes();
    sb.AppendLine("Scene saved.");
    return sb.ToString();
  }

  static void DumpChildren(Transform t, System.Text.StringBuilder sb, int depth, int maxDepth) {
    if (depth > maxDepth) return;
    string indent = new string(' ', depth * 2);
    foreach (Transform child in t) {
      sb.AppendLine(indent + child.name + "  localPos=" + child.localPosition.ToString("F5"));
      DumpChildren(child, sb, depth + 1, maxDepth);
    }
  }
}
